import React from "react";
import HTMLContent from "./HTMLContent";

export default function ContentView({ rows }: any) {
  return (
    <div>
      {rows.map((row: any) => (
        <div key={row.id} style={{ marginBottom: 40 }}>
          <h2>{row.name}</h2>
          <HTMLContent html={row.content} />
        </div>
      ))}
    </div>
  );
}