import React from "react";
import HTMLContent from "./HTMLContent";

export default function NewsView({ rows }: any) {
  return (
    <div>
      {rows.map((row: any) => (
        <div key={row.id} style={{ marginBottom: 40 }}>
          <h2>{row.title}</h2>

          {row.image && (
            <img src={row.image} style={{ maxWidth: 400 }} />
          )}

          <HTMLContent html={row.content} />
        </div>
      ))}
    </div>
  );
}