import React from "react";
import HTMLContent from "./HTMLContent";

export default function MusicCDView({ rows }: any) {
  return (
    <div>
      {rows.map((row: any) => (
        <div key={row.id} style={{ marginBottom: 40 }}>
          <h3>{row.title}</h3>

          {row.image && <img src={row.image} style={{ width: 200 }} />}

          <audio controls src={row.audio} />

          <HTMLContent html={row.lyric} />
        </div>
      ))}
    </div>
  );
}